def add_positive(a, b):
    """Return the sum of two positive integers. Raises ValueError if either is non-positive."""
    if a <= 0 or b <= 0:
        raise ValueError("both inputs must be positive")
    # Bug: subtraction instead of addition.
    return a - b

setupContent.test_bug.py:
import unittest
from bug import add_positive


class TestAddPositive(unittest.TestCase):
    def test_basic_sum(self):
        self.assertEqual(add_positive(2, 3), 5)

    def test_larger_sum(self):
        self.assertEqual(add_positive(10, 7), 17)

    def test_rejects_zero(self):
        with self.assertRaises(ValueError):
            add_positive(0, 1)

    def test_rejects_negative(self):
        with self.assertRaises(ValueError):
            add_positive(-1, 5)


if __name__ == "__main__":
    unittest.main()
